--
-- Name: sync_inventory_quantity(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.sync_inventory_quantity() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    UPDATE inventory_items
    SET quantity = (
        SELECT COALESCE(SUM(quantity), 0)
        FROM inventory_stocks
        WHERE item_id = COALESCE(NEW.item_id, OLD.item_id)
        AND is_archived = false
    )
    WHERE id = COALESCE(NEW.item_id, OLD.item_id);
    RETURN NEW;
END;
$$;


ALTER FUNCTION public.sync_inventory_quantity() OWNER TO postgres;

--
-- Name: trigger_update_client_stats(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.trigger_update_client_stats() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF TG_OP = 'DELETE' THEN
        PERFORM recalculate_client_stats(OLD.client_id);
        RETURN OLD;
    ELSE
        PERFORM recalculate_client_stats(NEW.client_id);
        -- Если client_id изменился, пересчитываем и старого клиента
        IF TG_OP = 'UPDATE' AND OLD.client_id != NEW.client_id THEN
            PERFORM recalculate_client_stats(OLD.client_id);
        END IF;
        RETURN NEW;
    END IF;
END;
$$;


ALTER FUNCTION public.trigger_update_client_stats() OWNER TO postgres;

