    name text NOT NULL,
    email text NOT NULL,
    role_id uuid,
    phone text,
    birthday date,
    avatar text,
    telegram text,
    instagram text,
    social_max text,
    department_id uuid,
    last_active_at timestamp without time zone,
    is_system boolean DEFAULT false NOT NULL,
    created_at timestamp without time zone DEFAULT now() NOT NULL,
    updated_at timestamp without time zone DEFAULT now() NOT NULL,
    email_verified boolean DEFAULT false NOT NULL,
    image text,
    two_factor_enabled boolean DEFAULT false
);


ALTER TABLE public.users OWNER TO postgres;

--
-- Name: verification_tokens; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE public.verification_tokens (
    id text NOT NULL,
    identifier text NOT NULL,
    value text NOT NULL,
    expires_at timestamp without time zone NOT NULL,
    created_at timestamp without time zone DEFAULT now()
);


ALTER TABLE public.verification_tokens OWNER TO postgres;

--
-- Name: wiki_folders; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE public.wiki_folders (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    name text NOT NULL,
    parent_id uuid,
    sort_order integer DEFAULT 0 NOT NULL,
    created_at timestamp without time zone DEFAULT now() NOT NULL
);


ALTER TABLE public.wiki_folders OWNER TO postgres;

--
-- Name: wiki_pages; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE public.wiki_pages (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    folder_id uuid,
    title text NOT NULL,
    content text,
    created_by uuid,
    updated_at timestamp without time zone DEFAULT now() NOT NULL,
    created_at timestamp without time zone DEFAULT now() NOT NULL
);


ALTER TABLE public.wiki_pages OWNER TO postgres;

--
-- Name: work_sessions; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE public.work_sessions (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    user_id uuid NOT NULL,
    camera_id uuid,
    date timestamp without time zone NOT NULL,
    start_time timestamp without time zone NOT NULL,
    end_time timestamp without time zone,
    duration_seconds integer DEFAULT 0,
    session_type public.session_type DEFAULT 'work'::public.session_type NOT NULL,
    created_at timestamp without time zone DEFAULT now() NOT NULL
);


ALTER TABLE public.work_sessions OWNER TO postgres;

--
-- Name: workstations; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE public.workstations (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    name character varying(255) NOT NULL,
    description text,
    camera_id uuid,
    assigned_user_id uuid,
    zone jsonb,
    color character varying(7) DEFAULT '#3B82F6'::character varying,
    sort_order integer DEFAULT 0,
    is_active boolean DEFAULT true,
    requires_assigned_user boolean DEFAULT false,
    last_seen_user_id uuid,
    last_seen_at timestamp without time zone,
    created_at timestamp without time zone DEFAULT now() NOT NULL,
    updated_at timestamp without time zone DEFAULT now() NOT NULL
);


ALTER TABLE public.workstations OWNER TO postgres;

--
-- Name: xiaomi_accounts; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE public.xiaomi_accounts (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    xiaomi_user_id character varying(50) NOT NULL,
    email character varying(255),
    nickname character varying(255),
    encrypted_token text NOT NULL,
    region character varying(10) DEFAULT 'cn'::character varying NOT NULL,
    is_active boolean DEFAULT true NOT NULL,
    last_sync_at timestamp without time zone,
    created_at timestamp without time zone DEFAULT now() NOT NULL,
    updated_at timestamp without time zone DEFAULT now() NOT NULL,
    created_by_id uuid
);


ALTER TABLE public.xiaomi_accounts OWNER TO postgres;

